    addLowpass(frequency) {
        let newNode = new FilterSoundNode(this.engine, new BiquadFilterNode(this.node.context, {
            type: "lowpass",
            frequency: frequency,
        }));
        this.node.connect(newNode.node);
        return newNode;
    }
    addHighpass(frequency) {
        let newNode = new FilterSoundNode(this.engine, new BiquadFilterNode(this.node.context, {
            type: "highpass",
            frequency: frequency,
        }));
        this.node.connect(newNode.node);
        return newNode;
    }
